import{_ as e,o as t,c as a,V as o}from"./chunks/framework.509d3f30.js";const g=JSON.parse('{"title":"Web interface","description":"","frontmatter":{},"headers":[],"relativePath":"overview/web-interface.md","filePath":"overview/web-interface.md"}'),r={name:"overview/web-interface.md"},i=o('<h1 id="web-interface" tabindex="-1">Web interface <a class="header-anchor" href="#web-interface" aria-label="Permalink to &quot;Web interface&quot;">​</a></h1><p>Registered FIB peers can log in to the FIB Web Interface using their registered credentials.</p><h2 id="home" tabindex="-1">Home <a class="header-anchor" href="#home" aria-label="Permalink to &quot;Home&quot;">​</a></h2><p>On this page peers can view the following tabs:</p><h3 id="consortium-data" tabindex="-1">Consortium Data <a class="header-anchor" href="#consortium-data" aria-label="Permalink to &quot;Consortium Data&quot;">​</a></h3><p>This tab provides a dynamic visual representation of the recent fraud data uploaded by peers on the network. The threat map shows real-time data on the type of fraud, the origination country, and the destination country, which allows users to quickly identify emerging trends and hotspots.</p><h3 id="fraud-twitter-feed" tabindex="-1">Fraud Twitter Feed <a class="header-anchor" href="#fraud-twitter-feed" aria-label="Permalink to &quot;Fraud Twitter Feed&quot;">​</a></h3><p>This tab provides a real-time view of customer fraud-related tweets for major cities around the globe. Peers can select countries to see what customers from those countries are posting to Twitter in relation to fraudulent activities. This allows users to gain valuable insights into the fraud-related concerns of telco customers globally and to identify emerging trends and patterns.</p><h2 id="analyse" tabindex="-1">Analyse <a class="header-anchor" href="#analyse" aria-label="Permalink to &quot;Analyse&quot;">​</a></h2><p>On this page peers can view a range of statistical metrics derived from the collected fraud event data stored on the network. This data can be visualized in a variety of charts and graphs, and can be filtered by fraud type, country of origination, contributing IP addresses or phone numbers, etc.</p><h2 id="upload" tabindex="-1">Upload <a class="header-anchor" href="#upload" aria-label="Permalink to &quot;Upload&quot;">​</a></h2><p>On this page peers can either upload fraud events or flag the existing ones.</p><p>See the following related tutorials:</p><ul><li><a href="./../tutorials-web/uploading-fraud-data.html">Uploading fraud data</a></li><li><a href="./../tutorials-web/flagging-fraud-data.html">Flagging fraud data</a></li></ul><h2 id="download" tabindex="-1">Download <a class="header-anchor" href="#download" aria-label="Permalink to &quot;Download&quot;">​</a></h2><p>On this page peers can download fraud events data.</p><p>See the following related tutorial:</p><ul><li><a href="./../tutorials-web/downloading-fraud-data.html">Downloading fraud data</a></li></ul><h2 id="tokens" tabindex="-1">Tokens <a class="header-anchor" href="#tokens" aria-label="Permalink to &quot;Tokens&quot;">​</a></h2><p>On this page peers can view their current balance.</p><h2 id="profile" tabindex="-1">Profile <a class="header-anchor" href="#profile" aria-label="Permalink to &quot;Profile&quot;">​</a></h2><p>On this page peers can view the following information about their account:</p><ul><li><strong>About</strong> tab — displays peer&#39;s contact information.</li><li><strong>Subscription</strong> tab — displays the following subscription information: <ul><li><strong>Membership type</strong>: the category of the company that a peer is registered with (e.g., telco, fraud vendor, etc.).</li><li><strong>Subscription type</strong>: the type of subscription that a peer has.</li><li><strong>Company name</strong>: the name of the company that a peer is registered with.</li><li><strong>Operating country</strong>: the country that a peer is operating from.</li></ul></li><li><strong>Services</strong> tab — displays whether a peer has access to the following FIB services: <ul><li><strong>Uploading</strong>: allows users to upload fraud events data on the <strong>Upload</strong> page.</li><li><strong>Web API</strong>: allows users to access backend API endpoints.</li><li><strong>Reports</strong>: allows users to access the fraud analytics reports on the <strong>Analyse</strong> page.</li></ul></li></ul><div class="tip custom-block"><p class="custom-block-title">Note</p><p>If you are a peer with a <strong>freemium</strong> subscription, you can select <strong>Request</strong> on the <strong>Subscription</strong> tab to make a request to change your subscription type to <strong>premium</strong>.</p></div>',24),n=[i];function s(l,d,h,c,u,p){return t(),a("div",null,n)}const b=e(r,[["render",s]]);export{g as __pageData,b as default};
